import{_ as t,o as r,c as a,ag as e}from"./chunks/framework.CvgP6Fyv.js";const v=JSON.parse('{"title":"CAS Overlay 开发版文档","description":"","frontmatter":{},"headers":[{"level":1,"title":"CAS Overlay 开发版文档","slug":"cas-overlay-开发版文档","link":"#cas-overlay-开发版文档","children":[{"level":2,"title":"项目简介","slug":"项目简介","link":"#项目简介","children":[]},{"level":2,"title":"版本选择","slug":"版本选择","link":"#版本选择","children":[{"level":3,"title":"CAS Overlay 7.3.x 系列","slug":"cas-overlay-7-3-x-系列","link":"#cas-overlay-7-3-x-系列","children":[]},{"level":3,"title":"CAS Overlay 6.6.x 系列","slug":"cas-overlay-6-6-x-系列","link":"#cas-overlay-6-6-x-系列","children":[]},{"level":3,"title":"CAS Overlay 5.3.x 系列","slug":"cas-overlay-5-3-x-系列","link":"#cas-overlay-5-3-x-系列","children":[]}]},{"level":2,"title":"版本对比","slug":"版本对比","link":"#版本对比","children":[]},{"level":2,"title":"核心功能","slug":"核心功能","link":"#核心功能","children":[]},{"level":2,"title":"技术支持","slug":"技术支持","link":"#技术支持","children":[]},{"level":2,"title":"快速开始","slug":"快速开始","link":"#快速开始","children":[]},{"level":2,"title":"注意事项","slug":"注意事项","link":"#注意事项","children":[]}]}],"relativePath":"dev/cas-overlay/index.md","filePath":"dev/cas-overlay/index.md"}'),o={name:"dev/cas-overlay/index.md"};function i(n,l,s,d,g,h){return r(),a("div",null,[...l[0]||(l[0]=[e('<h1 id="cas-overlay-开发版文档" tabindex="-1">CAS Overlay 开发版文档 <a class="header-anchor" href="#cas-overlay-开发版文档" aria-label="Permalink to &quot;CAS Overlay 开发版文档&quot;">​</a></h1><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p>CAS (Central Authentication Service) 是 Apereo 基金会维护的企业级开源单点登录系统，为企业应用提供统一的身份认证与授权机制。本项目基于不同版本的 CAS Overlay 进行定制化开发，提供完整的开发基座、配置模板和部署方案，旨在帮助开发者快速构建、定制和部署符合企业需求的 CAS 认证服务。</p><h2 id="版本选择" tabindex="-1">版本选择 <a class="header-anchor" href="#版本选择" aria-label="Permalink to &quot;版本选择&quot;">​</a></h2><p>根据您的技术栈和需求，选择适合的 CAS Overlay 版本：</p><h3 id="cas-overlay-7-3-x-系列" tabindex="-1">CAS Overlay 7.3.x 系列 <a class="header-anchor" href="#cas-overlay-7-3-x-系列" aria-label="Permalink to &quot;CAS Overlay 7.3.x 系列&quot;">​</a></h3><ul><li><strong>JDK 版本</strong>：21</li><li><strong>构建工具</strong>：Maven 3.9+ / Gradle 9.1.0</li><li><strong>数据库</strong>：MySQL 8.0.33</li><li><strong>缓存</strong>：Redis 7.2.4</li><li><strong>主要特性</strong>：最新版本，支持现代 Java 特性（Java 21），Spring Boot 3.x 架构，OIDC 动态客户端注册，JWT AccessToken 加密签名</li><li><strong>文档链接</strong>： <ul><li><a href="./cas-overlay-7.3.x-maven.html">Maven 版本</a></li><li><a href="./cas-overlay-7.3.x-gradle.html">Gradle 版本</a></li></ul></li></ul><h3 id="cas-overlay-6-6-x-系列" tabindex="-1">CAS Overlay 6.6.x 系列 <a class="header-anchor" href="#cas-overlay-6-6-x-系列" aria-label="Permalink to &quot;CAS Overlay 6.6.x 系列&quot;">​</a></h3><ul><li><strong>JDK 版本</strong>：11</li><li><strong>构建工具</strong>：Maven 3.9+ / Gradle 7.5</li><li><strong>数据库</strong>：MySQL 8.0.33</li><li><strong>缓存</strong>：Redis 7.2.4</li><li><strong>主要特性</strong>：稳定版本，广泛应用于生产环境，Spring Boot 2.x 架构</li><li><strong>文档链接</strong>： <ul><li><a href="./cas-overlay-6.6.x-maven.html">Maven 版本</a></li><li><a href="./cas-overlay-6.6.x-gradle.html">Gradle 版本</a></li></ul></li></ul><h3 id="cas-overlay-5-3-x-系列" tabindex="-1">CAS Overlay 5.3.x 系列 <a class="header-anchor" href="#cas-overlay-5-3-x-系列" aria-label="Permalink to &quot;CAS Overlay 5.3.x 系列&quot;">​</a></h3><ul><li><strong>JDK 版本</strong>：1.8</li><li><strong>构建工具</strong>：Maven 3.9+ / Gradle 7.5</li><li><strong>数据库</strong>：MySQL 8.0.33</li><li><strong>缓存</strong>：Redis 7.2.4</li><li><strong>主要特性</strong>：经典版本，适用于旧环境，支持传统 Servlet 规范</li><li><strong>文档链接</strong>： <ul><li><a href="./cas-overlay-5.3.x-maven.html">Maven 版本</a></li><li><a href="./cas-overlay-5.3.x-gradle.html">Gradle 版本</a></li></ul></li></ul><h2 id="版本对比" tabindex="-1">版本对比 <a class="header-anchor" href="#版本对比" aria-label="Permalink to &quot;版本对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>5.3.x</th><th>6.6.x</th><th>7.3.x</th></tr></thead><tbody><tr><td><strong>JDK</strong></td><td>1.8</td><td>11</td><td>21</td></tr><tr><td><strong>Spring Boot</strong></td><td>2.x</td><td>2.x</td><td>3.x</td></tr><tr><td><strong>Servlet API</strong></td><td>javax.servlet</td><td>javax.servlet</td><td>jakarta.servlet</td></tr><tr><td><strong>Gradle</strong></td><td>7.5</td><td>7.5</td><td>9.1.0</td></tr><tr><td><strong>MySQL</strong></td><td>8.0.33</td><td>8.0.33</td><td>8.0.33</td></tr><tr><td><strong>Redis</strong></td><td>7.2.4</td><td>7.2.4</td><td>7.2.4</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><p>所有版本的 CAS Overlay 开发版都包含以下核心功能：</p><ul><li><strong>架构转型</strong>：从传统 WAR 包架构升级为现代 JAR 包架构，简化部署流程，更好适配微服务环境和容器化部署</li><li><strong>数据库集成</strong>：集成 MyBatis 数据库访问框架，实现与各类关系型数据库的无缝对接</li><li><strong>自定义类启动CAS服务</strong>：提供 <code>CasWebApplication</code> 主启动类，支持开发者进行本地Debug启动和日常开发中的断点调试</li><li><strong>自定义认证验证</strong>：实现灵活的身份验证逻辑，支持自定义用户名密码的登录校验规则</li><li><strong>同时支持OAUTH2.0认证 和 OIDC认证</strong>：并实现自定义的认证返回值格式，支持自定义返回用户信息、角色信息或任意数据</li><li><strong>分布式集群部署</strong>：基于 Redis 支持分布式多节点部署，实现高可用性和扩展性</li><li><strong>安全加固</strong>：关闭 CAS 默认账号密码登录，强制使用自定义认证类，提升系统安全性</li><li><strong>资源提取</strong>：全量提取前端静态资源和模板，方便开发者根据企业品牌定制前端界面</li><li><strong>多语言支持</strong>：内置中文、英文等多语言支持，满足国际化需求（示例）</li><li><strong>容器化部署</strong>：内置DockerFile和Jenkins部署脚本，方便开发者进行容器化部署和持续集成</li></ul><h2 id="技术支持" tabindex="-1">技术支持 <a class="header-anchor" href="#技术支持" aria-label="Permalink to &quot;技术支持&quot;">​</a></h2><ul><li><strong>技术支持</strong>：北京必码科技工作室</li><li><strong>官方文档</strong>：<a href="https://bima.cc" target="_blank" rel="noreferrer">https://bima.cc</a></li><li><strong>官方店铺</strong>：<a href="https://bima.taobao.com" target="_blank" rel="noreferrer">https://bima.taobao.com</a></li><li><strong>联系邮箱</strong>：<a href="mailto:bima.cc@qq.com" target="_blank" rel="noreferrer">bima.cc@qq.com</a></li><li><strong>联系微信</strong>：e18929958</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><ol><li><strong>选择版本</strong>：根据您的 JDK 版本和构建工具偏好选择合适的 CAS Overlay 版本</li><li><strong>查看文档</strong>：点击上方对应版本的链接查看详细文档</li><li><strong>环境准备</strong>：按照文档要求准备 JDK、MySQL、Redis 等环境</li><li><strong>数据库初始化</strong>：执行提供的数据库初始化脚本（<code>db_uc_20260113.sql</code>）</li><li><strong>配置修改</strong>：根据您的环境修改数据库连接、Redis 连接等配置</li><li><strong>构建运行</strong>：使用 Maven 或 Gradle 构建并运行项目</li><li><strong>访问服务</strong>：通过 <code>https://服务器IP:8443/cas/login</code> 访问 CAS 服务</li></ol><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li><strong>安全提示</strong>：首次登录后请修改默认管理员密码</li><li><strong>证书警告</strong>：测试环境下访问会提示证书警告，可忽略或添加信任</li><li><strong>网络要求</strong>：构建过程需要访问 Maven 中央仓库，确保网络连接正常</li><li><strong>生产环境</strong>：在生产环境中使用前，请进行充分的测试和验证</li></ul>',22)])])}const u=t(o,[["render",i]]);export{v as __pageData,u as default};
